import base64
import os

work = "/Users/iliazlobin/Hermes/projects/sd-online-auction-backend-mvp-v2026.07.02.1"

# ci.yml content as base64 to avoid any encoding issues
ci_b64 = ""

# func.yml content as base64
func_b64 = ""

for fn, b64 in [("ci.yml", ci_b64), ("functional.yml", func_b64)]:
    content = base64.b64decode(b64).decode("utf-8")
    # Fix the placeholder patterns - {{ and }}
    content = content.replace("%7B%7B", "{{").replace("%7D%7D", "}}")
    content = content.replace("%7B", "{").replace("%7D", "}")

    path = os.path.join(work, ".github/workflows", fn)
    with open(path, "w") as f:
        f.write(content)
    print(f"Wrote {fn} ({len(content)} bytes)")

    # Verify
    with open(path, "rb") as f:
        data = f.read()
    idx = data.find(b"REDIS_URL:")
    after = data[idx : idx + 120]
    print(f"  {after}")
    print(f"  steps: count = {data.count(b'    steps:')}")
    print(f"  echo = {b'echo $!' in data}")
